   100→void
   101→ldap_int_tls_destroy( struct ldapoptions *lo )
   102→{
   103→	if ( lo->ldo_tls_ctx ) {
   104→		ldap_pvt_tls_ctx_free( lo->ldo_tls_ctx );
   105→		lo->ldo_tls_ctx = NULL;
   106→	}
   107→
   108→	if ( lo->ldo_tls_certfile ) {
   109→		LDAP_FREE( lo->ldo_tls_certfile );
   110→		lo->ldo_tls_certfile = NULL;
   111→	}
   112→	if ( lo->ldo_tls_keyfile ) {
   113→		LDAP_FREE( lo->ldo_tls_keyfile );
   114→		lo->ldo_tls_keyfile = NULL;
   115→	}
   116→	if ( lo->ldo_tls_dhfile ) {
   117→		LDAP_FREE( lo->ldo_tls_dhfile );
   118→		lo->ldo_tls_dhfile = NULL;
   119→	}
   120→	if ( lo->ldo_tls_ecname ) {
   121→		LDAP_FREE( lo->ldo_tls_ecname );
   122→		lo->ldo_tls_ecname = NULL;
   123→	}
   124→	if ( lo->ldo_tls_cacertfile ) {
   125→		LDAP_FREE( lo->ldo_tls_cacertfile );
   126→		lo->ldo_tls_cacertfile = NULL;
   127→	}
   128→	if ( lo->ldo_tls_cacertdir ) {
   129→		LDAP_FREE( lo->ldo_tls_cacertdir );
   130→		lo->ldo_tls_cacertdir = NULL;
   131→	}
   132→	if ( lo->ldo_tls_ciphersuite ) {
   133→		LDAP_FREE( lo->ldo_tls_ciphersuite );
   134→		lo->ldo_tls_ciphersuite = NULL;
   135→	}
   136→	if ( lo->ldo_tls_crlfile ) {
   137→		LDAP_FREE( lo->ldo_tls_crlfile );
   138→		lo->ldo_tls_crlfile = NULL;
   139→	}
   140→	/* tls_pin_hashalg and tls_pin share the same buffer */
   141→	if ( lo->ldo_tls_pin_hashalg ) {
   142→		LDAP_FREE( lo->ldo_tls_pin_hashalg );
   143→		lo->ldo_tls_pin_hashalg = NULL;
   144→	} else {
   145→		LDAP_FREE( lo->ldo_tls_pin.bv_val );
   146→	}
   147→	BER_BVZERO( &lo->ldo_tls_pin );
   148→}
   149→
   150→/*
   151→ * Tear down the TLS subsystem. Should only be called once.
   152→ */
   153→void
   154→ldap_pvt_tls_destroy( void )
   155→{
   156→	struct ldapoptions *lo = LDAP_INT_GLOBAL_OPT();   
   157→
   158→	ldap_int_tls_destroy( lo );
   159→
   160→	tls_imp->ti_tls_destroy();
   161→}
   162→
   163→/*
   164→ * Initialize a particular TLS implementation.
   165→ * Called once per implementation.
   166→ */
   167→static int
   168→tls_init(tls_impl *impl, int do_threads )
   169→{
   170→	static int tls_initialized = 0;
   171→
   172→	if ( !tls_initialized++ ) {
   173→#ifdef LDAP_R_COMPILE
   174→		ldap_pvt_thread_mutex_init( &tls_def_ctx_mutex );
   175→#endif
   176→	}
   177→
   178→	if ( impl->ti_inited++ ) return 0;
   179→
   180→	if ( do_threads ) {
   181→#ifdef LDAP_R_COMPILE
   182→		impl->ti_thr_init();
   183→#endif
   184→	}
   185→
   186→	return impl->ti_tls_init();
   187→}
   188→
   189→/*
   190→ * Initialize TLS subsystem. Called once per implementation.
   191→ */
   192→int
   193→ldap_pvt_tls_init( int do_threads )
   194→{
   195→	return tls_init( tls_imp, do_threads );
   196→}
