		return rc;
	}

	pin = LDAP_STRDUP( pin );
	p = strchr( pin, ':' );

	/* pubkey (its hash) goes in bv, alg in p */
	if ( p ) {
		*p = '\0';
		bv.bv_val = p+1;
		p = pin;
	} else {
		bv.bv_val = pin;
